-{"id":"frankenredis-lbjl","title":"Add conformance audit that flags dormant fixture files and planned live-oracle hooks","description":"Evidence: a simple fixture-vs-matrix diff still finds dormant files on disk that are not referenced by crates/fr-conformance/fixtures/live_oracle_matrix.json, and crates/fr-conformance/fixtures/user_workflow_corpus_v1.json still contains planned differential hooks that can silently drift from the actual harness. That gap is why FR-P2C-001, FR-P2C-006, and core_replication sat unwired without a failing test.\\n\\nNeed: add a harness-level audit test that scans the fixture directory, the live_oracle_matrix, and the user_workflow corpus, then fails when command/protocol/replay fixtures are present on disk without either matrix coverage or an explicit allowlist/exemption, and when workflow differential hooks stay planned without an explanatory exemption.\\n\\nReal impl path: crates/fr-conformance/src/lib.rs plus crates/fr-conformance/fixtures/live_oracle_matrix.json and, if needed, a small explicit exemption manifest under crates/fr-conformance/fixtures/.","status":"open","priority":2,"issue_type":"task","created_at":"2026-04-22T18:20:58.336422044Z","created_by":"cod-redis","updated_at":"2026-04-22T18:20:58.336422044Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["conformance","fr-conformance","harness","testing"]}
+{"id":"frankenredis-lbjl","title":"Add conformance audit that flags dormant fixture files and planned live-oracle hooks","description":"Evidence: a simple fixture-vs-matrix diff still finds dormant files on disk that are not referenced by crates/fr-conformance/fixtures/live_oracle_matrix.json, and crates/fr-conformance/fixtures/user_workflow_corpus_v1.json still contains planned differential hooks that can silently drift from the actual harness. That gap is why FR-P2C-001, FR-P2C-006, and core_replication sat unwired without a failing test.\\n\\nNeed: add a harness-level audit test that scans the fixture directory, the live_oracle_matrix, and the user_workflow corpus, then fails when command/protocol/replay fixtures are present on disk without either matrix coverage or an explicit allowlist/exemption, and when workflow differential hooks stay planned without an explanatory exemption.\\n\\nReal impl path: crates/fr-conformance/src/lib.rs plus crates/fr-conformance/fixtures/live_oracle_matrix.json and, if needed, a small explicit exemption manifest under crates/fr-conformance/fixtures/.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-22T18:20:58.336422044Z","created_by":"cod-redis","updated_at":"2026-04-22T21:14:32.495300781Z","closed_at":"2026-04-22T21:14:32.495300781Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0,"labels":["conformance","fr-conformance","harness","testing"]}
 {"id":"frankenredis-ld0","title":"Implement multi-database parity for SELECT, MOVE, and SWAPDB","description":"README.md and FEATURE_PARITY.md both identify multi-database support as a remaining parity gap. Implement db-isolated keyspace semantics, SELECT session switching, and correct MOVE/SWAPDB behavior without violating deterministic runtime semantics or persistence invariants.","status":"closed","priority":1,"issue_type":"feature","created_at":"2026-03-22T03:20:52.594983657Z","created_by":"ubuntu","updated_at":"2026-03-22T03:40:29.675321106Z","closed_at":"2026-03-22T03:40:29.674766797Z","close_reason":"SELECT accepts DB 0-15, SWAPDB accepts valid DB pairs (no-op in single-store mode). Error messages match Redis format. Fixtures updated.","source_repo":".","compaction_level":0,"original_size":0}
